import React, { useState } from 'react';
import { Box, TextField, IconButton, List, ListItem, ListItemText, Paper, Typography, Button } from '@mui/material';
import SendIcon from '@mui/icons-material/Send';
import Navbar from '../components/Navbar';

const BGPchat = () => {
    const [messages, setMessages] = useState([{ text: "Welcome to BGP-LLaMA Chat!", sender: "system" }]);
    const [currentMessage, setCurrentMessage] = useState('');
    const [chats, setChats] = useState([{ id: 1, name: "Chat 1" }]); // Track multiple chats

    const handleSendMessage = () => {
        if (currentMessage.trim() !== '') {
            setMessages([...messages, { text: currentMessage, sender: "user" }]);
            setCurrentMessage('');
        }
    };

    const handleMessageChange = (event) => {
        setCurrentMessage(event.target.value);
    };

    const handleKeyPress = (event) => {
        if (event.key === 'Enter' && !event.shiftKey) {
            handleSendMessage();
            event.preventDefault();
        }
    };

    const startNewChat = () => {
        const newChatId = chats.length + 1;
        setChats([...chats, { id: newChatId, name: `Chat ${newChatId}` }]);
        setMessages([{ text: "Start a new conversation!", sender: "system" }]);
    };

    return (
        <Box sx={{ display: 'flex', height: '100vh', overflow: 'hidden' }}>
            <Navbar />
            {/* Chat history sidebar */}
            <Box sx={{ width: '300px', borderRight: '1px solid #ccc', overflowY: 'auto' }}>
                <Typography variant="h6" sx={{ p: 2 }}>Chat History</Typography>
                {chats.map((chat) => (
                    <Button key={chat.id} sx={{ justifyContent: 'flex-start', textTransform: 'none', width: '100%', p: 2 }}>
                        {chat.name}
                    </Button>
                ))}
                <Button onClick={startNewChat} sx={{ width: '100%', mt: 2 }}>Start New Chat</Button>
            </Box>
            {/* Main chat interface */}
            <Box sx={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
                <Paper sx={{ flex: 1, overflow: 'auto', p: 2 }}>
                    <List sx={{ padding: 0 }}>
                        {messages.map((message, index) => (
                            <ListItem key={index} alignItems="flex-start" sx={{ display: 'flex', flexDirection: message.sender === 'system' ? 'row-reverse' : 'row' }}>
                                <ListItemText
                                    primary={message.text}
                                    primaryTypographyProps={{
                                        sx: {
                                            fontWeight: 'medium',
                                            color: message.sender === 'system' ? 'gray' : 'primary.main',
                                            textAlign: message.sender === 'system' ? 'right' : 'left',
                                            bgcolor: message.sender === 'system' ? '#f0f0f0' : '#e0f7fa',
                                            borderRadius: 2,
                                            p: 1,
                                        }
                                    }}
                                />
                            </ListItem>
                        ))}
                    </List>
                </Paper>
                <Box
                    component="form"
                    sx={{
                        display: 'flex',
                        alignItems: 'center',
                        p: 2
                    }}
                    onSubmit={(e) => { e.preventDefault(); handleSendMessage(); }}
                >
                    <TextField
                        label="Type your message..."
                        fullWidth
                        variant="outlined"
                        value={currentMessage}
                        onChange={handleMessageChange}
                        onKeyPress={handleKeyPress}
                        multiline
                        maxRows={4}
                        sx={{ mr: 1 }}
                    />
                    <IconButton color="primary" onClick={handleSendMessage}>
                        <SendIcon />
                    </IconButton>
                </Box>
            </Box>
        </Box>
    );
};

export default BGPchat;
